targets.expr:
topk(
  10,
  (
    sum by (job, serviceName, serviceType) (
      rate(
        requests_response_time_seconds_sum{
          job=~"$job",
          folderName=~"$folderName",
          serviceType=~"$serviceType",
          serviceName=~"$serviceName",
          operation=~"^.+$"
        }[5m]
      )
    )
    /
    sum by (job, serviceName, serviceType) (
      rate(
        requests_total{
          job=~"$job",
          folderName=~"$folderName",
          serviceType=~"$serviceType",
          serviceName=~"$serviceName",
          operation=~"$operation",
          operation=~"^.+$"
        }[5m]
      )
    )
  )
)
and
sum by (job, serviceName, serviceType) (
  rate(
    requests_total{
      job=~"$job",
      folderName=~"$folderName",
      serviceType=~"$serviceType",
      serviceName=~"$serviceName",
      operation=~"$operation",
      operation=~"^.+$"
    }[5m]
  )
) > 0

